from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a natural language sentence from a list of triples."""
    if not triples:
        return ""

    # Get the primary subject (most common subject in triples)
    subject_counts = {}
    for t in triples:
        subject_counts[t.subject] = subject_counts.get(t.subject, 0) + 1
    primary_subject = max(subject_counts, key=subject_counts.get)

    # Group triples by subject
    subject_triples = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Helper function to normalize nationality
    def normalize_nationality(nationality_str):
        # Convert plural nationalities to singular (e.g., "Americans" -> "American")
        if nationality_str.endswith("s") and len(nationality_str) > 2:
            return nationality_str[:-1]
        return nationality_str

    # Build the main sentence starting with the primary subject
    primary_triples = subject_triples.get(primary_subject, [])

    # Collect all information about the primary subject
    main_clauses = []
    creator_list = []
    other_info = []

    for t in primary_triples:
        if t.predicate == "creator":
            creator_list.append(t.object)
        elif t.predicate == "fullName":
            main_clauses.append(f"whose full name is {t.object}")
        elif t.predicate == "alternativeName":
            main_clauses.append(f"also known as {t.object}")
        elif t.predicate == "series":
            main_clauses.append(f"part of the series {t.object}")
        elif t.predicate == "firstAppearanceInFilm":
            main_clauses.append(f"first appearing in the film {t.object}")
        elif t.predicate == "voice":
            main_clauses.append(f"voiced by {t.object}")
        elif t.predicate == "nationality":
            nat = normalize_nationality(t.object)
            main_clauses.append(f"{t.subject} is {nat}")
        elif t.predicate == "award":
            main_clauses.append(f"{t.subject} received the {t.object}")
        elif t.predicate == "birthPlace":
            main_clauses.append(f"{t.subject} was born in {t.object}")
        elif t.predicate == "starring":
            main_clauses.append(f"{t.subject} stars {t.object}")
        elif t.predicate == "lastAired":
            main_clauses.append(f"{t.subject} last aired on {t.object}")
        elif t.predicate == "firstAired":
            main_clauses.append(f"{t.subject} first aired on {t.object}")
        elif t.predicate == "distributor":
            main_clauses.append(f"{t.subject} was distributed by {t.object}")
        elif t.predicate == "broadcastedBy":
            main_clauses.append(f"{t.subject} was broadcasted by {t.object}")
        elif t.predicate == "product":
            main_clauses.append(f"{t.subject} produces {t.object}")
        elif t.predicate == "foundedBy":
            main_clauses.append(f"{t.subject} was founded by {t.object}")
        elif t.predicate == "keyPerson":
            main_clauses.append(f"{t.subject} has key person {t.object}")
        elif t.predicate == "child":
            main_clauses.append(f"{t.subject} has a child named {t.object}")
        elif t.predicate == "city":
            main_clauses.append(f"{t.subject} is located in {t.object}")

    # Start building the sentence
    if creator_list:
        if len(creator_list) == 1:
            sentence = f"{primary_subject} was created by {creator_list[0]}"
        else:
            creators_str = " and ".join(creator_list[:-1]) + f", and {creator_list[-1]}" if len(creator_list) > 2 else " and ".join(creator_list)
            sentence = f"{primary_subject} was created by {creators_str}"
    else:
        sentence = primary_subject

    # Add other clauses with proper relative pronouns
    if main_clauses:
        # Find clauses that should use "who" vs standalone
        for clause in main_clauses:
            if primary_subject in clause or "is" in clause or "was" in clause:
                sentence += f", {clause}"
            else:
                sentence += f", {clause}"

    # Process other subjects and link them appropriately
    other_subjects = [s for s in subject_triples.keys() if s != primary_subject]
    for other_subject in other_subjects:
        other_triples = subject_triples[other_subject]
        for t in other_triples:
            if t.predicate == "creator":
                # Skip if already handled in primary subject
                continue
            elif t.predicate == "nationality":
                nat = normalize_nationality(t.object)
                sentence += f", {t.subject} is {nat}"
            elif t.predicate == "birthPlace":
                sentence += f", {t.subject} was born in {t.object}"
            elif t.predicate == "award":
                sentence += f", {t.subject} received the {t.object}"
            elif t.predicate == "starring":
                sentence += f", {t.subject} stars {t.object}"
            elif t.predicate == "series":
                sentence += f", {t.subject} is part of the series {t.object}"

    return sentence + "."

